import React, { InputHTMLAttributes } from "react";

interface InputProps extends InputHTMLAttributes<HTMLInputElement> {
  className?: string;
}

export const Input: React.FC<InputProps> = ({
  type = "text",
  placeholder = "Enter text",
  className = "",
  autoComplete,
  ...props
}) => {
  // Set default autocomplete values based on input type
  const defaultAutoComplete = autoComplete || (type === "password" ? "current-password" : type === "email" ? "email" : "off");
  
  return (
    <input
      type={type}
      placeholder={placeholder}
      autoComplete={autoComplete || defaultAutoComplete}
      className={`px-4 py-2 w-full border-2 shadow-md transition focus:outline-hidden focus:shadow-xs ${
        props["aria-invalid"]
          ? "border-red-500 text-red-500 shadow-xs shadow-red-600"
          : ""
      } ${className}`}
      {...props}
    />
  );
};
